// frontend/src/submit.js

// Build a cleaned payload: remove helper nodes, filter edges, compute counts and DAG flag
function buildCleanGraphPayload(nodes = [], edges = [], options = {}) {
  const excludeTypes = options.excludeTypes || ["deleteNode"];

  // 1) keep only nodes backend should see
  const keptNodes = nodes.filter((n) => !excludeTypes.includes(n.type));

  // 2) build a set of kept node ids
  const keptIds = new Set(keptNodes.map((n) => n.id));

  // 3) filter edges so both ends exist in keptIds
  const keptEdges = edges.filter((e) => keptIds.has(e.source) && keptIds.has(e.target));

  // 4) compute DAG boolean using topological sort
  const isDAG = checkIsDAG(keptNodes, keptEdges);

  return {
    nodes: keptNodes,
    edges: keptEdges,
    counts: { nodes: keptNodes.length, edges: keptEdges.length },
    dag: isDAG,
  };
}

// Topological sort / cycle detection
function checkIsDAG(nodes = [], edges = []) {
  const adj = new Map();
  const indeg = new Map();

  nodes.forEach((n) => {
    adj.set(n.id, []);
    indeg.set(n.id, 0);
  });

  edges.forEach((e) => {
    if (!adj.has(e.source) || !adj.has(e.target)) return;
    adj.get(e.source).push(e.target);
    indeg.set(e.target, (indeg.get(e.target) || 0) + 1);
  });

  const q = [];
  for (const [id, d] of indeg.entries()) if (d === 0) q.push(id);

  let visited = 0;
  while (q.length) {
    const u = q.shift();
    visited++;
    for (const v of adj.get(u) || []) {
      indeg.set(v, indeg.get(v) - 1);
      if (indeg.get(v) === 0) q.push(v);
    }
  }

  return visited === nodes.length;
}

// ============================================
// ENHANCED: COMPLETE PIPELINE SIMULATION ENGINE
// ============================================

// Generate test values for input nodes
function generateTestValues(nodes) {
  const testValues = {};
  let inputCounter = 1;
  let numberCounter = 10; // Start numbers at 10

  nodes.forEach(node => {
    if (node.type === 'inputNode') {
      const nodeId = node.id;
      const inputType = node.data?.inputType || 'Text';
      const inputName = node.data?.inputName || `input_${nodeId.slice(-4)}`;

      switch(inputType) {
        case 'Number':
          testValues[nodeId] = numberCounter;
          numberCounter += 10; // Increment by 10 for next number
          break;
        case 'File':
          testValues[nodeId] = `document_${inputCounter}.pdf`;
          break;
        case 'Boolean':
          testValues[nodeId] = inputCounter % 2 === 0; // Alternate true/false
          break;
        case 'Text':
        default:
          testValues[nodeId] = inputName;
          break;
      }
      inputCounter++;
    }
  });

  console.log("📋 Generated test values:", testValues);
  return testValues;
}

// Simulate data flow through the entire pipeline
function simulatePipeline(nodes, edges) {
  console.log("🔧 Starting pipeline simulation...");

  const testValues = generateTestValues(nodes);
  const nodeValues = new Map(); // Store values at each node
  const results = [];
  const outputNodeResults = new Map();

  // Initialize node values
  nodes.forEach(node => {
    if (testValues[node.id]) {
      nodeValues.set(node.id, testValues[node.id]);
    }
  });

  // Process each node in topological order (simplified)
  const processedNodes = new Set();

  // First, process all non-condition nodes
  nodes.forEach(node => {
    if (node.type !== 'conditionNode') {
      // Just pass values through for now
      const incomingEdges = edges.filter(e => e.target === node.id);
      if (incomingEdges.length > 0) {
        const firstIncomingEdge = incomingEdges[0];
        const sourceValue = nodeValues.get(firstIncomingEdge.source);
        if (sourceValue !== undefined) {
          nodeValues.set(node.id, sourceValue);
        }
      }
    }
  });

  // Now process condition nodes
  const conditionNodes = nodes.filter(n => n.type === 'conditionNode');
  conditionNodes.forEach(conditionNode => {
    const nodeId = conditionNode.id;
    const operator = conditionNode.data?.operator || '==';

    // Get input-a and input-b values
    const inputAEdge = edges.find(e => e.target === nodeId && e.targetHandle === 'input-a');
    const inputBEdge = edges.find(e => e.target === nodeId && e.targetHandle === 'input-b');

    if (inputAEdge && inputBEdge) {
      const valueA = nodeValues.get(inputAEdge.source);
      const valueB = nodeValues.get(inputBEdge.source);

      if (valueA !== undefined && valueB !== undefined) {
        // Evaluate condition
        const result = evaluateCondition(operator, valueA, valueB);

        // Store the condition result
        nodeValues.set(nodeId + '_result', result);
        nodeValues.set(nodeId + '_true', result); // Value for true port
        nodeValues.set(nodeId + '_false', !result); // Value for false port

        // Find output edges
        const trueEdges = edges.filter(e => 
          e.source === nodeId && e.sourceHandle === 'true'
        );
        const falseEdges = edges.filter(e => 
          e.source === nodeId && e.sourceHandle === 'false'
        );

        // Record what would happen
        results.push({
          condition_node_id: nodeId,
          operator,
          input_a: { value: valueA, from: inputAEdge.source },
          input_b: { value: valueB, from: inputBEdge.source },
          result,
          result_human: result ? 'TRUE' : 'FALSE',
          true_outputs: trueEdges.map(e => ({
            target: e.target,
            target_type: nodes.find(n => n.id === e.target)?.type
          })),
          false_outputs: falseEdges.map(e => ({
            target: e.target,
            target_type: nodes.find(n => n.id === e.target)?.type
          })),
          message: `Condition ${nodeId}: ${valueA} ${operator} ${valueB} = ${result ? 'TRUE' : 'FALSE'}`
        });

        // Propagate values to output nodes
        if (result) {
          trueEdges.forEach(edge => {
            nodeValues.set(edge.target, result);
          });
        } else {
          falseEdges.forEach(edge => {
            nodeValues.set(edge.target, !result); // false
          });
        }
      } else {
        results.push({
          condition_node_id: nodeId,
          error: 'Missing input values',
          message: `Condition ${nodeId}: Could not get values for both inputs`
        });
      }
    } else {
      results.push({
        condition_node_id: nodeId,
        error: 'Missing connections',
        message: `Condition ${nodeId}: Needs two inputs (A and B)`
      });
    }
  });

  // Collect output node results
  const outputNodes = nodes.filter(n => n.type === 'outputNode');
  outputNodes.forEach(outputNode => {
    const incomingEdges = edges.filter(e => e.target === outputNode.id);
    if (incomingEdges.length > 0) {
      const lastEdge = incomingEdges[incomingEdges.length - 1];
      const sourceValue = nodeValues.get(lastEdge.source);

      if (sourceValue !== undefined) {
        outputNodeResults.set(outputNode.id, {
          node: outputNode,
          value: sourceValue,
          source: lastEdge.source,
          source_type: nodes.find(n => n.id === lastEdge.source)?.type
        });
      }
    }
  });

  console.log("📈 Simulation complete:", { results, outputNodeResults: Array.from(outputNodeResults.entries()) });
  return { conditionResults: results, outputNodeResults };
}

// Evaluate a condition between two values
function evaluateCondition(operator, valueA, valueB) {
  console.log(`Evaluating: ${valueA} ${operator} ${valueB}`);

  // Try to convert to numbers if possible
  const numA = Number(valueA);
  const numB = Number(valueB);
  const isNumeric = !isNaN(numA) && !isNaN(numB);

  const a = isNumeric ? numA : String(valueA);
  const b = isNumeric ? numB : String(valueB);

  switch(operator) {
    case '==': return a == b;
    case '!=': return a != b;
    case '>': return a > b;
    case '<': return a < b;
    case '>=': return a >= b;
    case '<=': return a <= b;
    default: 
      console.warn(`Unknown operator: ${operator}`);
      return false;
  }
}

// Generate user-friendly summary
function generateSimulationSummary(conditionResults, outputNodeResults) {
  let summary = "🧪 PIPELINE SIMULATION RESULTS\n";
  summary += "=".repeat(50) + "\n\n";

  if (conditionResults.length === 0) {
    summary += "No condition nodes found.\n\n";
  } else {
    summary += "🔀 CONDITION EVALUATIONS:\n";
    conditionResults.forEach((result, index) => {
      if (result.error) {
        summary += `${index + 1}. ❌ ${result.condition_node_id}: ${result.error}\n`;
      } else {
        const icon = result.result ? '✅ TRUE' : '❌ FALSE';
        summary += `${index + 1}. ${icon} ${result.condition_node_id}:\n`;
        summary += `   Input A (from ${result.input_a.from}): ${result.input_a.value}\n`;
        summary += `   Input B (from ${result.input_b.from}): ${result.input_b.value}\n`;
        summary += `   Operation: ${result.input_a.value} ${result.operator} ${result.input_b.value}\n`;

        if (result.result) {
          summary += `   ↳ Routes TRUE to: ${result.true_outputs.map(o => `${o.target_type}(${o.target})`).join(', ') || 'nothing'}\n`;
        } else {
          summary += `   ↳ Routes FALSE to: ${result.false_outputs.map(o => `${o.target_type}(${o.target})`).join(', ') || 'nothing'}\n`;
        }
        summary += "\n";
      }
    });
  }

  if (outputNodeResults.size > 0) {
    summary += "📤 OUTPUT NODE RESULTS:\n";
    let outputIndex = 1;
    outputNodeResults.forEach((result, nodeId) => {
      summary += `${outputIndex}. ${result.node.data?.outputName || nodeId}:\n`;
      summary += `   Value: ${result.value}\n`;
      summary += `   Type: ${typeof result.value}\n`;
      summary += `   Source: ${result.source_type}(${result.source})\n`;
      summary += "\n";
      outputIndex++;
    });
  }

  summary += "=".repeat(50);
  return summary;
}

// ============================================
// MAIN SUBMIT FUNCTION
// ============================================

export async function submitPipeline(nodes, edges, setNodes) {
  try {
    console.log("🚀 Starting pipeline submission...");

    // Build clean payload (exclude deleteNode)
    const payload = buildCleanGraphPayload(nodes, edges, { excludeTypes: ["deleteNode"] });

    console.log("📊 Pipeline Stats:", {
      totalNodes: nodes.length,
      filteredNodes: payload.counts.nodes,
      totalEdges: edges.length,
      filteredEdges: payload.counts.edges,
      isDAG: payload.dag,
      nodeTypes: [...new Set(payload.nodes.map(n => n.type))]
    });

    // Run complete pipeline simulation
    const { conditionResults, outputNodeResults } = simulatePipeline(payload.nodes, payload.edges);
    const simulationSummary = generateSimulationSummary(conditionResults, outputNodeResults);

    console.log("🔍 Simulation Results:");
    console.log(simulationSummary);

    // Update output nodes with results
    if (setNodes && outputNodeResults.size > 0) {
      console.log("🔄 Updating output nodes with results...");

      setNodes(prevNodes => {
        return prevNodes.map(node => {
          const result = outputNodeResults.get(node.id);
          if (result) {
            return {
              ...node,
              data: {
                ...node.data,
                result: result.value,
                lastUpdated: new Date().toISOString()
              }
            };
          }
          return node;
        });
      });
    }

    // Prepare request body for backend
    const requestBody = {
      nodes: payload.nodes,
      edges: payload.edges,
      num_nodes: payload.counts.nodes,
      num_edges: payload.counts.edges,
      is_dag: payload.dag,
    };

    // Add simulation results if we have any
    if (conditionResults.length > 0) {
      requestBody.condition_results = conditionResults;
      requestBody.simulation_summary = simulationSummary;
    }

    console.log("📤 Sending to backend:", requestBody);

    // Send to backend
    const res = await fetch("http://127.0.0.1:8000/pipelines/parse", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(requestBody),
    });

    if (!res.ok) {
      throw new Error(`Backend error: ${res.status} ${res.statusText}`);
    }

    const data = await res.json();
    console.log("📥 Backend response:", data);

    // Build comprehensive alert message
    let alertMessage = simulationSummary + "\n\n";
    alertMessage += "🔷 BACKEND VALIDATION:\n";
    alertMessage += `• Nodes: ${data.num_nodes || payload.counts.nodes}\n`;
    alertMessage += `• Edges: ${data.num_edges || payload.counts.edges}\n`;
    alertMessage += `• DAG: ${data.is_dag ? '✅ YES' : '❌ NO'}\n`;

    if (data.pipeline_analysis) {
      alertMessage += `• Has Conditions: ${data.pipeline_analysis.has_conditions ? '✅ Yes' : '❌ No'}\n`;
      alertMessage += `• Input Nodes: ${data.pipeline_analysis.input_count || 0}\n`;
      alertMessage += `• Output Nodes: ${data.pipeline_analysis.output_count || 0}\n`;
    }

    alertMessage += "\n✅ Pipeline analysis complete! Output nodes have been updated.";

    // Show alert
    alert(alertMessage);

  } catch (err) {
    console.error("❌ submitPipeline error:", err);

    // User-friendly error message
    let errorMessage = "❌ Pipeline Submission Failed\n\n";
    errorMessage += `Error: ${err.message || 'Unknown error'}\n\n`;

    alert(errorMessage);
  }
}

export const SubmitButton = ({ nodes, edges, setNodes }) => (
  <button onClick={() => submitPipeline(nodes, edges, setNodes)}>
    Submit Pipeline
  </button>
);
